301	func ctxSleep(ctx context.Context, d time.Duration) error {
302		if d <= 0 {
303			return nil
304		}
305		t := time.NewTimer(d)
306		defer t.Stop()
307		select {
308		case <-ctx.Done():
309			return ctx.Err()
310		case <-t.C:
311			return nil
312		}
313	}
