88	func TestParseRetryAfter(t *testing.T) {
89		now := time.Date(2026, 5, 3, 12, 0, 0, 0, time.UTC)
90		cases := []struct {
91			in   string
92			want time.Duration
93		}{
94			{"30", 30 * time.Second},
95			{"  60 ", 60 * time.Second},
96			{"-5", 0}, // negative seconds → zero
97			{"", 0},
98			{"15s", 15 * time.Second},
99			{"2m", 2 * time.Minute},
100		}
101		for _, c := range cases {
102			got := ParseRetryAfter(c.in, now)
103			if got != c.want {
104				t.Errorf("ParseRetryAfter(%q): got %v; want %v", c.in, got, c.want)
105			}
